parameters.jsCode:
const item = $input.first().json;
const body = item.body || item;
return [{ json: { engagement_id: body.engagement_id } }];

const stats = $('Get Engagement Stats').first().json;
const topFindings = $('Get Top 5 Findings').all().map(i => i.json);
const owaspBreakdown = $('Get OWASP Breakdown').all().map(i => i.json);
const engId = $('Normalize').first().json.engagement_id;

// Determine overall risk posture
let riskPosture = 'Low';
if (parseInt(stats.criticals) > 0) riskPosture = 'Critical';
else if (parseInt(stats.highs) > 2) riskPosture = 'High';
else if (parseInt(stats.highs) > 0 || parseInt(stats.mediums) > 3) riskPosture = 'Medium';

// Build executive narrative
const totalFindings = parseInt(stats.criticals||0) + parseInt(stats.highs||0) + parseInt(stats.mediums||0) + parseInt(stats.lows||0);
const remediationPriority = topFindings.map((f,i) => `${i+1}. [${f.severity.toUpperCase()}] ${f.title} (${f.asset_value}) — Score: ${f.recon_score}/10`);

const executiveSummary = {
  engagement: {
    client: stats.client_name,
    name: stats.engagement_name,
    type: stats.type,
    period: `${stats.testing_window_start?.split('T')[0]} to ${stats.testing_window_end?.split('T')[0]}`
  },
  risk_posture: riskPosture,
  findings_summary: {
    total: totalFindings,
    critical: parseInt(stats.criticals||0),
    high: parseInt(stats.highs||0),
    medium: parseInt(stats.mediums||0),
    low: parseInt(stats.lows||0),
    fixed: parseInt(stats.fixed||0),
    recurring: parseInt(stats.recurring||0),
    average_risk_score: parseFloat(stats.avg_score||0)
  },
  asset_coverage: {
    total_in_scope: parseInt(stats.total_assets||0),
    tested: parseInt(stats.assets_tested||0),
    coverage_pct: parseFloat(stats.coverage_pct||0)
  },
  top_priority_actions: remediationPriority,
  owasp_categories_affected: owaspBreakdown.map(o => `${o.owasp_category}: ${o.count} finding(s)`),
  key_observations: [
    parseInt(stats.recurring||0) > 0 ? `${stats.recurring} finding(s) are recurring from prior engagements — indicating systemic weaknesses.` : null,
    riskPosture === 'Critical' ? 'At least one critical-severity finding requires immediate remediation.' : null,
    parseFloat(stats.coverage_pct||0) < 80 ? `Asset coverage is ${stats.coverage_pct}% — some in-scope assets were not fully tested.` : null
  ].filter(Boolean),
  generated_at: new Date().toISOString()
};

return [{ json: { engagement_id: engId, executive_summary: executiveSummary } }];

