INSERT INTO reports (engagement_id, report_type, status, metadata)
VALUES ('{{ $json.engagement_id }}','executive','draft','{{ JSON.stringify($json.executive_summary).replace(/'/g,"''") }}'::jsonb)
RETURNING id;
